  674  /* All placements: never overflow the parent */
#sas_53422 {
  width: 100% 
  max-width: 100% !important;
  margin: 0 auto 1rem !important;
  box-sizing: border-box !important;
}

#sas_53422 [id^="sas_relDivPlayer_"] {
  display: block !important;
}

#sas_53422 video {
  display: block !important;
  width: 100% !important;
  max-width: 100% !important;
  height: auto !important;
}

/* Article body only: allow a larger video area */
.body-inject--video #sas_53422 {
  max-width: 680px !important;
}

